import { escapeXml } from "./utils";

async function aemetIsobarsFeed(request: Request, env: Env): Promise<Response> {
  const cacheKey = "aemet_isobars_feed";
  const NOW = new Date();
  const madridTZ = "Europe/Madrid";

  // Helper to get parts in Europe/Madrid
  const dtf = new Intl.DateTimeFormat("en-GB", {
    timeZone: madridTZ,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    hour12: false
  });
  const parts = Object.fromEntries(dtf.formatToParts(NOW).map(p => [p.type, p.value]));
  const hourCEST = parseInt(parts.hour, 10);

  // Spanish month names
  const spanishMonths = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio",
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];

  // Determine map reference (previous day 12h if before 12, else today 00h)
  let mapDate = new Date(NOW);
  let mapHour: string;
  if (hourCEST < 12) {
    mapDate = new Date(mapDate.getTime() - 24 * 60 * 60 * 1000);
    mapHour = "12";
  } else {
    mapHour = "00";
  }

  const mapParts = Object.fromEntries(
    new Intl.DateTimeFormat("en-GB", {
      timeZone: madridTZ,
      year: "numeric",
      month: "2-digit",
      day: "2-digit"
    }).formatToParts(mapDate).map(p => [p.type, p.value])
  );

  const mapMonthNum = mapParts.month;
  const mapDay = mapParts.day;
  const mapMonthEs = spanishMonths[parseInt(mapMonthNum, 10) - 1];

  let contentHtml: string = "";
  let title: string = "";
  let entryid: string = "";
  let apiSuccess: boolean = false;

  // Cache strategy: update every 6h (maps appear twice daily)
  const CACHE_TTL_MS = 3 * 60 * 60 * 1000; // 3h grace
  const cached = await env.RSS_CACHE.get(cacheKey, { type: "json" }) as any;

  if (cached && Date.now() - cached.timestamp < CACHE_TTL_MS) {
    title = cached.title;
    contentHtml = cached.contentHtml;
    entryid = cached.entryid;
    apiSuccess = cached.apiSuccess;
  }

  if (!apiSuccess) {
    // Fetch AEMET API (first level)
    const apiUrl = "https://opendata.aemet.es/opendata/api/mapasygraficos/analisis";
    let imageDataBase64: string | null = null;
    let imageUrl: string | null = null;

    try {
      const metaResp = await fetch(apiUrl, {
        headers: {
          "accept": "application/json",
          "api_key": env.AEMET_API_KEY
        }
      });

      if (metaResp.ok) {
        const metaJson: AEMETresponse = await metaResp.json();
        imageUrl = metaJson.datos || null;

        if (imageUrl) {
          const imgResp = await fetch(imageUrl);

          if (imgResp.ok) {
            const bodyStream = imgResp.body;

            if (bodyStream) {
              const processedResp = (await env.IMAGES
                .input(bodyStream)
                .transform({ rotate: 90 })
                .output({ format: "image/png" })
              ).response();
              const rotatedArrayBuffer = await processedResp.arrayBuffer();
              // Convert png image to base64
              imageDataBase64 = toBase64(new Uint8Array(rotatedArrayBuffer));
              apiSuccess = true;
              
            }
          }
        }
      }
    } catch (e) {
      console.error("error retrieving image");
    }

    if (!imageDataBase64) {
      imageDataBase64 = ""
    }
    entryid = `${parseInt(mapDay, 10)}-${mapMonthEs}-${mapHour.replace(":", "")}-isobaras-aemet`;
    title = `Mapa isobaras, a ${parseInt(mapDay, 10)} de ${mapMonthEs}, ${mapHour} horas`;

    contentHtml =
      `<div xmlns="http://www.w3.org/1999/xhtml"><img alt="${title}" src="data:image/png;base64,${imageDataBase64}" />` +
      `<p>Imagen obtenida de <a href="https://www.aemet.es/es/portada" target="_blank" rel="noreferrer" title="AEMET" aria-label="AEMET">AEMET</a> a través de su <a href="https://opendata.aemet.es/dist/index.html?#/mapas-y-graficos/Mapas%20de%20an%C3%A1lisis.%20%C3%9Altima%20pasada." target="_blank" rel="noreferrer" title="AEMET Opendata APIs" aria-label="AEMET Opendata APIs">API</a>. Feed RSS creado por <a href="https://laro.dev" target="_blank" rel="noreferrer" title="laro.dev" aria-label="laro.dev">laro.dev</a>.</p></div>`;
  }
  const feedid = `fd29424f-56ac-4f59-aadd-0fbccb3bd636`;
  const feedTitle = `Mapa de isobaras`;
  const description = "Estos mapas muestran la configuración de la presión en superficie usando isobaras (lineas de igual presión), áreas de alta (A, a) y baja (B, b) presión y los frentes en Europa y el Atlántico Norte.El mapa de análisis presenta el estado de la atmósfera a la hora correspondiente y los fenómenos más relevantes observados en España. Periodicidad de actualización: cada 12 horas (00, 12).";
  const feedUrl = "https://rss.laro.dev/aemet/mapa-isobaras.xml";
  const sourceUrl = "https://www.aemet.es/es/portada";
  const publishedRFC3339 = new Date().toISOString().replace(/\.\d{3}Z$/, "Z");

  // Generate RSS XML
  const feed = `<?xml version="1.0" encoding="utf-8"?>
<?xml-stylesheet href="/feed.xsl" type="text/xsl"?>
<feed xmlns="http://www.w3.org/2005/Atom"  
      xmlns:media="http://search.yahoo.com/mrss/"
      xml:lang="es-ES" 
      xml:base="${feedUrl}" >
    <title>${escapeXml(feedTitle)}</title>
    <author>
        <name>laro.dev</name>
        <email>hello@laro.dev</email>
    </author>
    <link rel='self' type='application/atom+xml' href='${feedUrl}' />
    <subtitle>${escapeXml(description)}</subtitle>
    <id>urn:uuid:${feedid}</id>
    <icon>/favicon-aemet.ico</icon>
    <updated>${publishedRFC3339}</updated>
    <entry>
      <title>${escapeXml(title)}</title>
      <link rel='alternate' type='type/html' href='${sourceUrl}' />
      <id>${entryid}</id>
      <published>${publishedRFC3339}</published>
      <updated>${publishedRFC3339}</updated>
      <summary type="xhtml">${contentHtml}</summary>
      <content type="xhtml">${contentHtml}</content>
    </entry>
</feed>`;

  if (!cached || (!cached.apiSuccess && apiSuccess)) {
    await env.RSS_CACHE.put(cacheKey, JSON.stringify({
      timestamp: Date.now(),
      apiSuccess,
      title,
      contentHtml,
      entryid
    }), {
      expirationTtl: 4 * 60 * 60 // 6h
    });
  }

  return new Response(feed, {
    headers: {
      "Content-Type": "application/xml; charset=utf-8",
      "cache-control": "public, max-age=1800"
    }
  });
}

function toBase64(bytes: Uint8Array): string {
  let binary = "";
  const chunk = 0x8000;
  for (let i = 0; i < bytes.length; i += chunk) {
    binary += String.fromCharCode(...bytes.subarray(i, i + chunk));
  }
  return btoa(binary);
}


interface AEMETresponse {
  descripcion: string;
  estado: number;
  datos: string;
  metadatos: string;
}

export { aemetIsobarsFeed };